import boto3
import os
import re
import subprocess
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from botocore.exceptions import NoCredentialsError

app = Flask(__name__)

ALLOWED_DOMAINS = ['example.com', 'anotherdomain.com']
S3_BUCKET = 'your-s3-bucket-name'
AWS_ACCESS_KEY = 'your-access-key'
AWS_SECRET_KEY = 'your-secret-key'
AWS_REGION = 'your-region'

def is_allowed_url(url):
    domain = re.findall(r'://(www\.)?([^/]+)', url)
    if domain and domain[0][1] in ALLOWED_DOMAINS:
        return True
    return False

def is_private_ip(ip):
    private_ip_patterns = [
        re.compile(r'^10\..*'),
        re.compile(r'^172\.(1[6-9]|2[0-9]|3[0-1])\..*'),
        re.compile(r'^192\.168\..*'),
        re.compile(r'^127\..*'),
        re.compile(r'^169\.254\..*')
    ]
    return any(pattern.match(ip) for pattern in private_ip_patterns)

def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--no-sandbox")
    driver = webdriver.Chrome(options=chrome_options)
    driver.set_window_size(1280, 720)
    driver.get(url)
    screenshot = driver.get_screenshot_as_png()
    driver.quit()
    return screenshot

def upload_to_s3(file_content, file_name):
    s3 = boto3.client('s3', aws_access_key_id=AWS_ACCESS_KEY, aws_secret_access_key=AWS_SECRET_KEY, region_name=AWS_REGION)
    try:
        s3.put_object(Bucket=S3_BUCKET, Key=file_name, Body=file_content, ContentType='image/png')
        return f"https://{S3_BUCKET}.s3.amazonaws.com/{file_name}"
    except NoCredentialsError:
        return None

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    url = request.json.get('url')
    if not url or not is_allowed_url(url):
        return jsonify({'error': 'Invalid or disallowed URL'}), 400

    screenshot = take_screenshot(url)
    file_name = f"screenshots/{os.path.basename(url)}.png"
    s3_url = upload_to_s3(screenshot, file_name)

    if s3_url:
        return jsonify({'s3_url': s3_url}), 200
    else:
        return jsonify({'error': 'Failed to upload to S3'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)